SELECT age_group, COUNT(division_id) AS number_of_divisions
FROM divisions
GROUP BY age_group;

SELECT AVG(ps.goals_scored) AS average_goals_scored
FROM players p
JOIN player_statistics ps ON p.player_id = ps.player_id;

SELECT player_id, injury_date, injury_type, expected_return
FROM injuries
WHERE injury_date LIKE '2023-05-%';
